const raw = $('Webhook').first().json.body || {};
const originalPrompt = (raw.prompt || raw.text || '').trim();
let enhanced = $input.first().json.message?.content || originalPrompt || 'a beautiful landscape';
// Strip any <think>...</think> tags from reasoning models
enhanced = enhanced.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
const channelId = raw.channel || raw.channel_id || 'C0AKW7W9ZPX';
const userId    = raw.user_id || raw.user || '';
const clientId  = 'n8n-img-' + Date.now();
const seed = Math.floor(Math.random() * 1_000_000_000);

// Flux1-Schnell FP8 workflow
// Models: flux1-schnell-fp8.safetensors (unet), clip_l + t5xxl_fp8_e4m3fn (clip), ae.safetensors (vae)
// Pipeline: UNETLoader → DualCLIPLoader → VAELoader → CLIPTextEncode → EmptyLatentImage
//           → RandomNoise → BasicGuider → KSamplerSelect → BasicScheduler → SamplerCustomAdvanced
//           → VAEDecode → SaveImage
const workflow = {
  "1": {
    "inputs": { "unet_name": "flux1-schnell-fp8.safetensors", "weight_dtype": "fp8_e4m3fn" },
    "class_type": "UNETLoader"
  },
  "2": {
    "inputs": {
      "clip_name1": "clip_l.safetensors",
      "clip_name2": "t5xxl_fp8_e4m3fn.safetensors",
      "type": "flux"
    },
    "class_type": "DualCLIPLoader"
  },
  "3": {
    "inputs": { "vae_name": "ae.safetensors" },
    "class_type": "VAELoader"
  },
  "4": {
    "inputs": { "text": enhanced, "clip": ["2", 0] },
    "class_type": "CLIPTextEncode"
  },
  "5": {
    "inputs": { "width": 1024, "height": 1024, "batch_size": 1 },
    "class_type": "EmptyLatentImage"
  },
  "6": {
    "inputs": { "noise_seed": seed },
    "class_type": "RandomNoise"
  },
  "7": {
    "inputs": {
      "model": ["1", 0],
      "conditioning": ["4", 0]
    },
    "class_type": "BasicGuider"
  },
  "8": {
    "inputs": { "sampler_name": "euler" },
    "class_type": "KSamplerSelect"
  },
  "9": {
    "inputs": {
      "model": ["1", 0],
      "scheduler": "simple",
      "steps": 4,
      "denoise": 1.0
    },
    "class_type": "BasicScheduler"
  },
  "10": {
    "inputs": {
      "noise": ["6", 0],
      "guider": ["7", 0],
      "sampler": ["8", 0],
      "sigmas": ["9", 0],
      "latent_image": ["5", 0]
    },
    "class_type": "SamplerCustomAdvanced"
  },
  "11": {
    "inputs": { "samples": ["10", 0], "vae": ["3", 0] },
    "class_type": "VAEDecode"
  },
  "12": {
    "inputs": { "filename_prefix": "n8n_flux", "images": ["11", 0] },
    "class_type": "SaveImage"
  }
};

// Store original prompt for Slack display; enhanced is used for generation only
return [{ json: { workflow, clientId, channelId, userId, prompt: originalPrompt } }];

const http = require('http');

function httpGetComfyUI(path) {
  return new Promise((resolve, reject) => {
    const req = http.get({ host: 'host.docker.internal', port: 8188, path }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        try { resolve(JSON.parse(Buffer.concat(chunks).toString())); }
        catch { resolve({}); }
      });
    });
    req.on('error', reject);
  });
}

const promptId  = $input.first().json.prompt_id;
const maxTries  = 72;          // 6 min @ 5s each

for (let i = 0; i < maxTries; i++) {
  await new Promise(r => setTimeout(r, 5000));
  const history = await httpGetComfyUI(`/history/${promptId}`);
  const entry = history[promptId];
  if (entry?.status?.completed) {
    const imageNode = Object.values(entry.outputs || {}).find(o => o.images?.length);
    if (imageNode) {
      const img = imageNode.images[0];
      const buildData = $('Build ComfyUI Payload').first().json;
      return [{ json: {
        promptId,
        filename:  img.filename,
        subfolder: img.subfolder || '',
        type:      img.type || 'output',
        channelId: buildData.channelId,
        userId:    buildData.userId,
        prompt:    buildData.prompt,
        mediaType: 'image'
      }}];
    }
  }
}
throw new Error('ComfyUI generation timed out after 6 minutes');

const https = require('https');

function postMessage(body) {
  return new Promise((resolve, reject) => {
    const data = JSON.stringify(body);
    const req = https.request({
      method: 'POST', hostname: 'slack.com', path: '/api/chat.postMessage',
      headers: {
        'Authorization': `Bearer ${$env.SLACK_BOT_TOKEN}`,
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(data)
      }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        try { resolve(JSON.parse(Buffer.concat(chunks).toString())); }
        catch { resolve({}); }
      });
    });
    req.on('error', reject);
    req.write(data);
    req.end();
  });
}

const ctx = $input.first().json;
const channelId = ctx.channelId || 'C0AKW7W9ZPX';
const prompt = ctx.prompt || '';
const filename = encodeURIComponent(ctx.filename || '');
const subfolder = encodeURIComponent(ctx.subfolder || '');
const type = ctx.type || 'output';
const mediaType = ctx.mediaType || 'image';

// Build public URL via n8n preview webhook → ComfyUI proxy
const ngrokBase = ($env.WEBHOOK_URL || '').replace(/\/$/, '');
const imageUrl = `${ngrokBase}/webhook/preview-comfyui?filename=${filename}&subfolder=${subfolder}&type=${type}`;

const isVideo = mediaType === 'gif';
const titleText = isVideo ? ':film_frames: Video Generated' : ':art: Image Generated';
const modelNote = isVideo ? 'Flux1-Schnell GIF on RTX 5070 Ti' : 'Flux1-Schnell on RTX 5070 Ti';

const blocks = [
  { type: 'header', text: { type: 'plain_text', text: titleText } },
  { type: 'section', text: { type: 'mrkdwn', text: `*Prompt:* ${prompt.slice(0, 200)}` } },
  { type: 'image', image_url: imageUrl, alt_text: 'Generated output' },
  { type: 'context', elements: [{ type: 'mrkdwn', text: `_${modelNote} · ${new Date().toLocaleTimeString()}_` }] }
];

const result = await postMessage({
  channel: channelId,
  text: `${titleText}: ${prompt.slice(0, 80)}`,
  blocks
});

if (!result.ok) {
  throw new Error(`Slack post failed: ${result.error || JSON.stringify(result)}`);
}

return [{ json: { ok: true, ts: result.ts, channel: result.channel, channelId } }];

// Restore context from Poll Until Done node (HTTP Request dropped it)
const poll = $('Poll Until Done').first().json;
const item = $input.first();
return [{
  json: {
    channelId: poll.channelId || '',
    filename: poll.filename || 'file',
    prompt: poll.prompt || '',
    uploadComment: poll.uploadComment || '{}'
  },
  binary: item.binary
}];
